@page "/directory"
@rendermode InteractiveServer
@inject IEmployeeService EmployeeService

<PageTitle>Employee Directory</PageTitle>

<div class="directory-container">
    @* Top Summary Bar *@
    <div class="kpi-bar">
        <div class="kpi-card">
            <div class="kpi-value">@totalEmployees</div>
            <div class="kpi-label">Total Employees</div>
        </div>
        <div class="kpi-card">
            <div class="kpi-value">@numberOfDepartments</div>
            <div class="kpi-label">Departments</div>
        </div>
        <div class="kpi-card">
            <div class="kpi-value">@averageTenure.ToString("F1")</div>
            <div class="kpi-label">Avg Tenure (years)</div>
        </div>
        <div class="kpi-card">
            <div class="kpi-value">@numberOfLocations</div>
            <div class="kpi-label">Locations</div>
        </div>
    </div>

    @* Main Content *@
    <div class="directory-body">
        @* Left Sidebar *@
        <div class="sidebar">
            <div class="filters">
                <input type="text" class="filter-input" placeholder="Search by name..."
                       @bind="searchQuery" @bind:event="oninput" />

                <select class="filter-select" @bind="selectedDepartment">
                    <option value="">All Departments</option>
                    @foreach (var dept in departments)
                    {
                        <option value="@dept">@dept</option>
                    }
                </select>

                <select class="filter-select" @bind="selectedLocation">
                    <option value="">All Locations</option>
                    @foreach (var loc in locations)
                    {
                        <option value="@loc">@loc</option>
                    }
                </select>

                <div class="filter-buttons">
                    <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
                    <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
                </div>
            </div>

            <div class="employee-list">
                @foreach (var emp in filteredEmployees)
                {
                    <div class="employee-card @(selectedEmployee?.Id == emp.Id ? "selected" : "")"
                         @onclick="() => SelectEmployee(emp)">
                        <div class="avatar-circle">@GetInitials(emp.Name)</div>
                        <div class="card-info">
                            <div class="card-name">@emp.Name</div>
                            <div class="card-title">@emp.Title</div>
                            <span class="department-badge" style="background-color: @GetDepartmentColor(emp.Department)">@emp.Department</span>
                        </div>
                    </div>
                }
            </div>
        </div>

        @* Main Content Area *@
        <div class="main-content">
            @if (selectedEmployee is null)
            {
                <div class="placeholder-message">
                    <p>Select an employee to view details</p>
                </div>
            }
            else
            {
                <div class="detail-panel">
                    <div class="detail-header">
                        <div class="avatar-large">@GetInitials(selectedEmployee.Name)</div>
                        <div class="detail-header-info">
                            <h2>@selectedEmployee.Name</h2>
                            <p class="detail-title">@selectedEmployee.Title</p>
                            <span class="department-badge" style="background-color: @GetDepartmentColor(selectedEmployee.Department)">@selectedEmployee.Department</span>
                            <p class="detail-location">📍 @selectedEmployee.Location</p>
                        </div>
                    </div>

                    <div class="info-grid">
                        <div class="info-item">
                            <span class="info-label">Email</span>
                            <span class="info-value">@selectedEmployee.Email</span>
                        </div>
                        <div class="info-item">
                            <span class="info-label">Hire Date</span>
