    margin-bottom: 2rem;
}

.info-item {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.info-label {
    font-size: 0.75rem;
    text-transform: uppercase;
    color: #888;
    letter-spacing: 0.5px;
    font-weight: 600;
}

.info-value {
    font-size: 0.95rem;
    color: #333;
}

/* Direct Reports */
.direct-reports-section h3 {
    margin-bottom: 1rem;
    font-size: 1.1rem;
}

.direct-reports-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
    gap: 0.75rem;
}

.direct-reports-list .employee-card {
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
}

.direct-reports-list .employee-card:hover {
    border-color: #1a73e8;
    background: #e8f0fe;
}

/* Footer */
