}

.avatar-large {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    background: #1a73e8;
    color: #fff;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.5rem;
    font-weight: 700;
    flex-shrink: 0;
}

.detail-header-info h2 {
    margin: 0;
    font-size: 1.5rem;
}

.detail-title {
    color: #555;
    margin: 0.25rem 0;
}

.detail-location {
    color: #666;
    margin: 0.5rem 0 0;
    font-size: 0.9rem;
}

/* Info Grid */
