    letter-spacing: 0.5px;
    font-weight: 600;
}

.info-value {
    font-size: 0.95rem;
    color: #333;
}

/* Direct Reports */
.direct-reports-section h3 {
    margin-bottom: 1rem;
    font-size: 1.1rem;
}

.direct-reports-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
